-- ============================================================================
-- Quiz Seed: Deuteronomy — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
-- ============================================================================

-- ═══ Deuteronomy Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 1, 'kids', 1, 'Who was speaking to the Israelites in Deuteronomy chapter 1?', 'Moses', 'Aaron', 'Joshua', 'Caleb', 'a', 'Deuteronomy 1:1 — "These be the words which Moses spake unto all Israel."'),
('Deuteronomy', 1, 'kids', 2, 'Where were the Israelites camped when Moses gave this speech?', 'In Egypt', 'In the wilderness on the other side of Jordan', 'In Canaan', 'At Mount Sinai', 'a', 'Deuteronomy 1:1 — "These be the words which Moses spake unto all Israel on this side Jordan in the wilderness."'),
('Deuteronomy', 1, 'kids', 3, 'Moses sent men to spy out the land. What land were they spying?', 'Egypt', 'Canaan', 'Moab', 'Edom', 'a', 'Deuteronomy 1:22 — "Let us send men before us, and they shall search us out the land."'),
-- Teens
('Deuteronomy', 1, 'teens', 1, 'What were the judges Moses appointed instructed to do?', 'Collect taxes for the tabernacle', 'Hear causes between brethren and judge righteously', 'Teach the law in every city', 'Lead the army into battle', 'a', 'Deuteronomy 1:16 — "Hear the causes between your brethren, and judge righteously between every man and his brother."'),
('Deuteronomy', 1, 'teens', 2, 'What did the ten unfaithful spies say about the people of Canaan?', 'They were friendly and would share the land', 'They were greater and taller than us and their cities walled up to heaven', 'They were few in number and easily defeated', 'They had already fled from Israel', 'a', 'Deuteronomy 1:28 — "The people is greater and taller than we; the cities are great and walled up to heaven."'),
('Deuteronomy', 1, 'teens', 3, 'Which two spies gave a good report and remained faithful?', 'Moses and Aaron', 'Caleb and Joshua', 'Reuben and Gad', 'Phinehas and Eleazar', 'a', 'Deuteronomy 1:36-38 — Caleb wholly followed the LORD, and Joshua the son of Nun shall go in.'),
('Deuteronomy', 1, 'teens', 4, 'What did God say would happen to the faithless generation?', 'They would wander forty years and not see the promised land', 'They would be enslaved again in Egypt', 'They would be destroyed immediately', 'They would be scattered among other nations', 'a', 'Deuteronomy 1:35 — "Surely there shall not one of these men of this evil generation see that good land."'),
('Deuteronomy', 1, 'teens', 5, 'When Israel attempted to go up and fight after being told they could not, what happened?', 'They won a great victory', 'The Amorites chased them and smote them in Seir', 'God sent fire to stop them', 'The Canaanites surrendered', 'a', 'Deuteronomy 1:44 — "And the Amorites...came out against you, and chased you, as bees do, and destroyed you in Seir."'),
-- Adults
('Deuteronomy', 1, 'adults', 1, 'In what year after leaving Egypt did Moses begin his address in Deuteronomy 1?', 'The twentieth year', 'The fortieth year, in the eleventh month', 'The thirtieth year', 'The thirty-eighth year', 'a', 'Deuteronomy 1:3 — "And it came to pass in the fortieth year, in the eleventh month...that Moses spake."'),
('Deuteronomy', 1, 'adults', 2, 'What was Moses'' complaint about judging the people alone?', 'He was too old to hear all cases', 'He could not bear the burden alone because God had multiplied them as the stars of heaven', 'The people refused to obey his rulings', 'He lacked wisdom to decide difficult matters', 'a', 'Deuteronomy 1:9-10 — "I am not able to bear you myself alone...the LORD your God hath multiplied you, and, behold, ye are this day as the stars of heaven for multitude."'),
('Deuteronomy', 1, 'adults', 3, 'What qualification did Moses require of the judges he appointed?', 'Men of great wealth and property', 'Wise men, and understanding, and known among their tribes', 'Men who had served in the tabernacle', 'Firstborn sons of each tribe', 'a', 'Deuteronomy 1:13 — "Take you wise men, and understanding, and known among your tribes, and I will make them rulers over you."'),
('Deuteronomy', 1, 'adults', 4, 'What principle of justice did Moses command the judges regarding persons?', 'Show respect to elders above all others', 'Ye shall not respect persons in judgment; hear the small as well as the great', 'Favor the testimony of priests above laymen', 'Defer all difficult cases to the Levites', 'a', 'Deuteronomy 1:17 — "Ye shall not respect persons in judgment; but ye shall hear the small as well as the great."'),
('Deuteronomy', 1, 'adults', 5, 'How did Moses describe the wilderness journey from Horeb to Kadesh-barnea?', 'A journey of eleven days', 'A journey of forty years', 'A journey of three months', 'A journey of seven days', 'a', 'Deuteronomy 1:2 — "There are eleven days'' journey from Horeb by the way of mount Seir unto Kadesh-barnea."'),
('Deuteronomy', 1, 'adults', 6, 'What comparison did Moses use to describe how God carried Israel through the wilderness?', 'As an eagle carries her young on her wings', 'As a shepherd carries a lamb', 'As a man doth bear his son', 'As a mother carries her child', 'a', 'Deuteronomy 1:31 — "The LORD thy God bare thee, as a man doth bear his son, in all the way that ye went."'),
('Deuteronomy', 1, 'adults', 7, 'Why was Moses told he would not lead Israel into the promised land?', 'Because he was too old', 'Because God was angry with him also on Israel''s account', 'Because he had worshipped idols', 'Because he refused to go to Pharaoh', 'a', 'Deuteronomy 1:37 — "Also the LORD was angry with me for your sakes, saying, Thou also shalt not go in thither."'),
('Deuteronomy', 1, 'adults', 8, 'After the failed attack on the Amorites, where did the Israelites return and weep before the LORD?', 'At the foot of Mount Sinai', 'In Kadesh', 'At the tabernacle entrance', 'Beside the Jordan River', 'a', 'Deuteronomy 1:45 — "And ye returned and wept before the LORD; but the LORD would not hearken to your voice."');

-- ═══ Deuteronomy Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 2, 'kids', 1, 'How many years did Israel wander in the wilderness?', 'Twenty years', 'Forty years', 'Ten years', 'Fifty years', 'a', 'Deuteronomy 2:14 — "And the space in which we came from Kadesh-barnea...was thirty and eight years."'),
('Deuteronomy', 2, 'kids', 2, 'Who was the king of Heshbon that Israel defeated?', 'Og', 'Sihon', 'Balak', 'Pharaoh', 'a', 'Deuteronomy 2:26 — "And I sent messengers out of the wilderness of Kedemoth unto Sihon king of Heshbon."'),
('Deuteronomy', 2, 'kids', 3, 'God told Israel not to fight against the people of which land because He had given it to the sons of Lot?', 'Canaan', 'Moab', 'Egypt', 'Edom', 'a', 'Deuteronomy 2:9 — "And the LORD said unto me, Distress not the Moabites, neither contend with them in battle: for I will not give thee of their land for a possession; because I have given Ar unto the children of Lot for a possession."'),
-- Teens
('Deuteronomy', 2, 'teens', 1, 'God told Israel to pass through the border of Edom carefully. Why were they not to provoke the Edomites?', 'Because the Edomites were too powerful', 'Because God had given Mount Seir to Esau and they were brethren of Israel', 'Because Israel had made a treaty with them', 'Because the Edomites worshipped the LORD', 'a', 'Deuteronomy 2:4-5 — "Ye are to pass through the coast of your brethren...take ye good heed unto yourselves...for I will not give you of their land, no, not so much as a foot breadth; because I have given mount Seir unto Esau for a possession."'),
('Deuteronomy', 2, 'teens', 2, 'What instruction did God give Israel concerning the Ammonites?', 'Destroy them completely', 'Distress them not, nor meddle with them', 'Make a covenant of peace with them', 'Tax them as tributaries', 'a', 'Deuteronomy 2:19 — "And when thou comest nigh over against the children of Ammon, distress them not, nor meddle with them: for I will not give thee of the land of the children of Ammon any possession."'),
('Deuteronomy', 2, 'teens', 3, 'What offer of peace did Moses make to Sihon king of Heshbon?', 'Tribute and taxes each year', 'Let us pass through thy land; we will go along by the high way', 'Allow Israel to settle in part of his kingdom', 'Surrender and become Israel''s servants', 'a', 'Deuteronomy 2:27 — "Let me pass through thy land: I will go along by the high way, I will neither turn unto the right hand nor to the left."'),
('Deuteronomy', 2, 'teens', 4, 'Why did Sihon refuse to let Israel pass through his land?', 'Because Moses had offended him', 'Because the LORD hardened his spirit and made his heart obstinate', 'Because his army was large enough to defeat Israel', 'Because he feared Israel would take his women and children', 'a', 'Deuteronomy 2:30 — "But Sihon king of Heshbon would not let us pass by him: for the LORD thy God hardened his spirit, and made his heart obstinate."'),
('Deuteronomy', 2, 'teens', 5, 'What happened to all the cities of Sihon after Israel''s victory?', 'They were left standing for Israel to inhabit', 'They were utterly destroyed — men, women, and children', 'They were given to the Levites as an inheritance', 'They paid tribute to Israel', 'a', 'Deuteronomy 2:34 — "And we took all his cities at that time, and utterly destroyed the men, and the women, and the little ones of every city, we left none to remain."'),
-- Adults
('Deuteronomy', 2, 'adults', 1, 'What event marked the end of the generation of warriors who had been condemned to die in the wilderness?', 'The crossing of the Red Sea', 'When all the men of war from among the people had consumed and died', 'The death of Aaron on Mount Hor', 'The capture of Sihon''s kingdom', 'a', 'Deuteronomy 2:14-15 — "Until all the generation of the men of war were wasted out from among the host...for indeed the hand of the LORD was against them, to destroy them from among the host."'),
('Deuteronomy', 2, 'adults', 2, 'What were the original inhabitants of Moab called before the Moabites drove them out?', 'Rephaim', 'Emims', 'Nephilim', 'Anakim', 'a', 'Deuteronomy 2:10-11 — "The Emims dwelt therein in times past, a people great, and many, and tall, as the Anakims; which also were accounted giants, as the Anakims."'),
('Deuteronomy', 2, 'adults', 3, 'What were the original inhabitants of Ammon called, who were displaced before the Ammonites settled there?', 'Horim', 'Zamzummims', 'Emims', 'Anakims', 'a', 'Deuteronomy 2:20 — "That also was accounted a land of giants: giants dwelt therein in old time; and the Ammonites call them Zamzummims."'),
('Deuteronomy', 2, 'adults', 4, 'God told Israel they were to buy meat and water from the Edomites with silver. What reason did He give for this?', 'To show generosity to all nations', 'Because the LORD had blessed Israel in all the works of their hands and He knew their walking through the great wilderness', 'To fulfil the covenant with Abraham', 'Because Israel had not yet enough supplies', 'a', 'Deuteronomy 2:7 — "For the LORD thy God hath blessed thee in all the works of thy hand: he knoweth thy walking through this great wilderness."'),
('Deuteronomy', 2, 'adults', 5, 'Where did Israel turn after going through the wilderness of Moab, before confronting Sihon?', 'Through the valley of Arnon', 'Through the plains of Jericho', 'Beside the brook Zered', 'Through the mountain of Seir', 'a', 'Deuteronomy 2:13 — "Now rise up, said I, and get you over the brook Zered. And we went over the brook Zered."'),
('Deuteronomy', 2, 'adults', 6, 'What specific promise did God make to Israel when delivering Sihon into their hands?', 'I will begin to put the dread of thee and the fear of thee upon the nations under the whole heaven', 'I will send hornets before thee to drive out the nations', 'I will make thee a terror to all kingdoms', 'Mine angel shall go before thee', 'a', 'Deuteronomy 2:25 — "This day will I begin to put the dread of thee and the fear of thee upon the nations that are under the whole heaven."'),
('Deuteronomy', 2, 'adults', 7, 'Which territory did Israel possess after defeating Sihon, according to chapter 2?', 'All the land of the Anakims', 'From Arnon unto Jabbok and from the wilderness unto the Jordan', 'The whole of the land of Canaan', 'The territory of Bashan only', 'a', 'Deuteronomy 2:36-37 — "From Aroer, which is by the brink of the river of Arnon...there was not one city too strong for us."'),
('Deuteronomy', 2, 'adults', 8, 'The Horim were the original inhabitants of Seir whom Esau''s descendants dispossessed. What parallel does this establish in the narrative?', 'That all Gentile nations were given land by God', 'That God had sovereignly given each people their territorial inheritance just as He was giving Canaan to Israel', 'That the Horim were relatives of the Israelites', 'That military conquest is always justified', 'a', 'Deuteronomy 2:12 — "As Israel did unto the land of his possession, which the LORD gave unto them" — paralleling Esau''s dispossession of Horim with Israel''s coming dispossession of Canaan.');

-- ═══ Deuteronomy Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 3, 'kids', 1, 'Who was the giant king of Bashan that Israel defeated?', 'Sihon', 'Og', 'Goliath', 'Pharaoh', 'a', 'Deuteronomy 3:1 — "Then we turned, and went up the way to Bashan: and Og the king of Bashan came out against us."'),
('Deuteronomy', 3, 'kids', 2, 'Moses was not allowed to cross the Jordan River. Who would lead Israel instead?', 'Aaron', 'Caleb', 'Joshua', 'Eleazar', 'a', 'Deuteronomy 3:28 — "But charge Joshua, and encourage him, and strengthen him: for he shall go over before this people."'),
('Deuteronomy', 3, 'kids', 3, 'How large was the iron bed of King Og of Bashan?', 'Five cubits long', 'Nine cubits long and four wide', 'Twelve cubits long', 'Seven cubits long', 'a', 'Deuteronomy 3:11 — "His bedstead was a bedstead of iron...nine cubits was the length thereof, and four cubits the breadth of it."'),
-- Teens
('Deuteronomy', 3, 'teens', 1, 'What did God say to Moses before the battle against Og to give him courage?', 'Fear him not, for I have delivered him into thy hand', 'I will send fire from heaven to destroy him', 'The LORD your God fights for you', 'Take courage, for the LORD is with thee', 'a', 'Deuteronomy 3:2 — "And the LORD said unto me, Fear him not: for I will deliver him, and all his people, and his land, into thy hand."'),
('Deuteronomy', 3, 'teens', 2, 'How many cities did Israel take in the region of Argob in Bashan?', 'Twelve', 'Twenty', 'Threescore', 'Forty', 'a', 'Deuteronomy 3:4 — "And we took all his cities at that time, there was not a city which we took not from them, threescore cities."'),
('Deuteronomy', 3, 'teens', 3, 'Which tribes received the territory of Sihon and Og east of the Jordan?', 'Judah, Simeon, and Levi', 'Reuben, Gad, and the half tribe of Manasseh', 'Ephraim, Benjamin, and Dan', 'Issachar, Zebulun, and Naphtali', 'a', 'Deuteronomy 3:12-13 — "And this land...I gave unto the Reubenites and to the Gadites. And the rest of Gilead, and all Bashan...gave I unto the half tribe of Manasseh."'),
('Deuteronomy', 3, 'teens', 4, 'What condition did Moses place on the warriors of Reuben, Gad, and half-Manasseh before they could inherit their land east of Jordan?', 'They must first build cities of refuge', 'They must pass armed before their brethren into Canaan until the LORD gave rest to all Israel', 'They must pay tribute for ten years', 'They must study the law for one year', 'a', 'Deuteronomy 3:18 — "I commanded you at that time, saying...ye shall pass over armed before your brethren the children of Israel."'),
('Deuteronomy', 3, 'teens', 5, 'What was Moses'' earnest prayer to God at the end of chapter 3?', 'That the Israelites would obey the law', 'That God would let him cross over and see the good land beyond Jordan', 'That Joshua would be made strong', 'That Israel would destroy all the Canaanites', 'a', 'Deuteronomy 3:25 — "I pray thee, let me go over, and see the good land that is beyond Jordan, that goodly mountain, and Lebanon."'),
-- Adults
('Deuteronomy', 3, 'adults', 1, 'What comparison does Moses draw between the victory over Og and the earlier victory over Sihon?', 'As I did unto Sihon king of Heshbon, so the LORD our God delivered Og also unto us', 'The victory over Og was greater because he was a giant', 'The victory over Og required less fighting because the cities were smaller', 'Og surrendered willingly while Sihon fought to the death', 'a', 'Deuteronomy 3:2 — The LORD said "Fear him not" and delivered him as He did Sihon, establishing a pattern of divine conquest.'),
('Deuteronomy', 3, 'adults', 2, 'What distinguished the cities of the plain from the fenced cities taken from Og?', 'The plain cities were given to the priests', 'The fenced cities had high walls, gates, and bars; the unwalled country villages were many', 'The plain cities were burned but the fenced cities kept intact', 'The fenced cities were given to Levites and the plain cities to warriors', 'a', 'Deuteronomy 3:5 — "All these cities were fenced with high walls, gates, and bars; beside unwalled towns a great many."'),
('Deuteronomy', 3, 'adults', 3, 'What note does Moses include about the Rephaim to explain Og''s gigantic size?', 'Og was the last of the Anakim', 'Og was the last of the remnant of giants', 'Og was descended from Nephilim through Ham', 'Og was born of a human mother and angelic father', 'a', 'Deuteronomy 3:11 — "For only Og king of Bashan remained of the remnant of giants; behold, his bedstead was a bedstead of iron."'),
('Deuteronomy', 3, 'adults', 4, 'What was the name of the Amorite territory that Jair of Manasseh captured and renamed?', 'He called it Gilead', 'He called it Havoth-jair after himself', 'He called it Bashan-havoth', 'He called it Argob', 'a', 'Deuteronomy 3:14 — "Jair the son of Manasseh took all the country of Argob unto the coasts of Geshuri and Maachathi; and called them after his own name, Bashan-havoth-jair."'),
('Deuteronomy', 3, 'adults', 5, 'What mountain was Moses permitted to climb to view the promised land he could not enter?', 'Mount Sinai', 'The top of Pisgah', 'Mount Hor', 'Mount Nebo', 'a', 'Deuteronomy 3:27 — "Get thee up into the top of Pisgah, and lift up thine eyes westward, and northward, and southward, and eastward, and behold it with thine eyes."'),
('Deuteronomy', 3, 'adults', 6, 'How did God respond to Moses'' prayer to cross the Jordan?', 'God promised to reconsider', 'The LORD was wroth and told Moses to speak no more of that matter', 'God told Moses to wait until Joshua led Israel across', 'God was silent and gave no answer', 'a', 'Deuteronomy 3:26 — "But the LORD was wroth with me for your sakes, and would not hear me: and the LORD said unto me, Let it suffice thee; speak no more unto me of this matter."'),
('Deuteronomy', 3, 'adults', 7, 'What was the primary responsibility Moses gave Joshua regarding the conquest?', 'To administer the law and judge the people', 'To go over this Jordan — thou shalt cause them to inherit the land', 'To build the tabernacle in Canaan', 'To lead worship after crossing the Jordan', 'a', 'Deuteronomy 3:28 — "Charge Joshua, and encourage him, and strengthen him: for he shall go over before this people, and he shall cause them to inherit the land."'),
('Deuteronomy', 3, 'adults', 8, 'Beth-peor is mentioned as the location opposite which Moses spoke to Israel. What significance does this place have later in the Pentateuch?', 'It was the place of Moses'' death and burial', 'It was where Israel sinned with Baal-peor in Numbers 25', 'It was the first city conquered in Canaan', 'It was the location of the tabernacle', 'a', 'Deuteronomy 3:29 — "So we abode in the valley over against Beth-peor" — the same valley where Israel had earlier committed idolatry at Baal-peor (Numbers 25).');

-- ═══ Deuteronomy Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 4, 'kids', 1, 'Moses told Israel not to make statues or pictures of what kind of things to worship?', 'Only animals', 'Any figure from heaven, earth, or water', 'Only the sun and moon', 'Only idols made of gold', 'a', 'Deuteronomy 4:16-18 — Israel was commanded not to make any graven image of any figure, the likeness of male or female, beast, bird, creeping thing, or fish.'),
('Deuteronomy', 4, 'kids', 2, 'Moses set apart three special cities east of the Jordan River for what purpose?', 'For priests to live in', 'For people who accidentally killed someone to flee to for safety', 'For the tribes to worship in', 'For storing the army''s weapons', 'a', 'Deuteronomy 4:41-42 — "Then Moses severed three cities on this side Jordan...that the slayer might flee thither, which should kill his neighbour unawares."'),
('Deuteronomy', 4, 'kids', 3, 'What did Moses say God was like that made Him different from any idol?', 'God was like a powerful king', 'God was like a consuming fire', 'God was like a bright light', 'God was like a mighty warrior', 'a', 'Deuteronomy 4:24 — "For the LORD thy God is a consuming fire, even a jealous God."'),
-- Teens
('Deuteronomy', 4, 'teens', 1, 'Why did Moses warn Israel not to add to or subtract from God''s commandments?', 'Because Moses had written them perfectly', 'So that they might keep them and be seen as wise and understanding in the eyes of the nations', 'Because the priests would punish them', 'Because only priests were allowed to interpret the law', 'a', 'Deuteronomy 4:2,6 — "Ye shall not add unto the word...that ye might keep the commandments...for this is your wisdom and your understanding in the sight of the nations."'),
('Deuteronomy', 4, 'teens', 2, 'What happened at Baal-peor that Moses used as a warning to Israel?', 'The tabernacle was destroyed by fire', 'All who followed Baal-peor were destroyed; those who held fast to the LORD all lived', 'Israel was defeated in battle', 'A plague killed the Levites', 'a', 'Deuteronomy 4:3-4 — "Your eyes have seen what the LORD did because of Baal-peor: for all the men that followed Baal-peor, the LORD thy God hath destroyed them...but ye that did cleave unto the LORD your God are alive every one of you."'),
('Deuteronomy', 4, 'teens', 3, 'What unique privilege did Moses say no other nation had compared to Israel?', 'A land flowing with milk and honey', 'A great nation with God so nigh unto them as the LORD was to Israel', 'The largest army of all peoples', 'A king who was chosen by God', 'a', 'Deuteronomy 4:7 — "What nation is there so great, who hath God so nigh unto them, as the LORD our God is in all things that we call upon him for?"'),
('Deuteronomy', 4, 'teens', 4, 'What did Moses predict would happen if Israel made idols and did evil in the land?', 'They would lose one battle but recover', 'They would be scattered among the nations and serve gods of wood and stone', 'Their crops would fail for seven years', 'Their firstborn would be taken', 'a', 'Deuteronomy 4:27-28 — "The LORD shall scatter you among the nations...and there ye shall serve gods, the work of men''s hands, wood and stone."'),
('Deuteronomy', 4, 'teens', 5, 'What hope did Moses give Israel even if they were scattered among the nations for idolatry?', 'God would raise up a new prophet like Moses', 'If they sought the LORD with all their heart they would find Him and He would not forsake them', 'A new generation would inherit the land', 'God would destroy all their enemies', 'a', 'Deuteronomy 4:29-31 — "But if from thence thou shalt seek the LORD thy God, thou shalt find him, if thou seek him with all thy heart...he will not forsake thee."'),
-- Adults
('Deuteronomy', 4, 'adults', 1, 'What theological argument does Moses make from the Horeb theophany to forbid image worship?', 'God is too holy to be represented', 'Ye saw no manner of similitude on the day the LORD spake out of the fire — therefore take heed lest ye make a graven image', 'God commanded that no artist could depict divine things', 'The Ten Commandments were written on stone to show God''s permanence', 'a', 'Deuteronomy 4:12,15 — "Ye heard the voice of the words, but saw no similitude...Take ye therefore good heed unto yourselves; for ye saw no manner of similitude."'),
('Deuteronomy', 4, 'adults', 2, 'Moses commands Israel to teach the covenant statutes diligently to their children. What specific domestic context does he describe?', 'In the synagogue every Sabbath', 'When thou sittest in thine house, walkest by the way, liest down, and risest up', 'During the annual feasts at the tabernacle', 'When the priests visit each family', 'a', 'Deuteronomy 4 connects to chapter 6:7 where Moses says to teach them diligently...when thou sittest in thine house, and when thou walkest by the way.'),
('Deuteronomy', 4, 'adults', 3, 'What is the unique claim Moses makes about Israel''s law compared to the statutes of other nations?', 'Israel''s law was written by God Himself on stone', 'What nation is there so great, that hath statutes and judgments so righteous as all this law?', 'Israel''s law covers more subjects than any other code', 'Only Israel''s law includes ceremonial, civil, and moral categories', 'a', 'Deuteronomy 4:8 — "And what nation is there so great, that hath statutes and judgments so righteous as all this law, which I set before you this day?"'),
('Deuteronomy', 4, 'adults', 4, 'What are the three cities of refuge Moses designated east of Jordan in chapter 4?', 'Hebron, Shechem, and Kedesh', 'Bezer, Ramoth in Gilead, and Golan in Bashan', 'Peniel, Mahanaim, and Succoth', 'Aroer, Dibon, and Medeba', 'a', 'Deuteronomy 4:43 — "Namely, Bezer in the wilderness...Ramoth in Gilead...and Golan in Bashan."'),
('Deuteronomy', 4, 'adults', 5, 'How does Moses describe the covenant God made at Horeb in terms of its intended recipients?', 'God made it with the patriarchs Abraham, Isaac, and Jacob', 'Not with our fathers, but with us, even us, who are all of us here alive this day', 'God made it with all mankind through Noah', 'God made it with Moses alone as representative', 'a', 'Deuteronomy 5:3 (anticipated in ch 4) — "The LORD made not this covenant with our fathers, but with us, even us, who are all of us here alive this day."'),
('Deuteronomy', 4, 'adults', 6, 'What comprehensive statement about the LORD''s uniqueness does Moses make in Deuteronomy 4:35?', 'The LORD is the strongest of all gods', 'The LORD he is God; there is none else beside him', 'The LORD is the creator of heaven and earth alone', 'The LORD is God of Israel only', 'a', 'Deuteronomy 4:35 — "Unto thee it was shewed, that thou mightest know that the LORD he is God; there is none else beside him."'),
('Deuteronomy', 4, 'adults', 7, 'For what purpose did Moses say God brought Israel out of Egypt with signs, wonders, and a mighty hand?', 'To give them the most fertile land on earth', 'To bring them in, to give them the land, and to drive out nations greater and mightier than they', 'To show all nations that Israel was His favourite', 'To establish a priestly kingdom for all peoples', 'a', 'Deuteronomy 4:37-38 — "He brought thee out in his sight with his mighty power out of Egypt; to drive out nations from before thee greater and mightier than thou art."'),
('Deuteronomy', 4, 'adults', 8, 'What eschatological dimension does Moses include in Deuteronomy 4 regarding Israel''s future repentance?', 'God would send a new Moses to restore them', 'In the latter days Israel would turn to the LORD and He would not forget the covenant sworn to the fathers', 'Israel would build a new temple greater than Solomon''s', 'A king like David would gather the scattered tribes', 'a', 'Deuteronomy 4:30-31 — "When thou art in tribulation, and all these things are come upon thee, even in the latter days, if thou turn to the LORD thy God...he will not forget the covenant of thy fathers."');

-- ═══ Deuteronomy Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 5, 'kids', 1, 'Moses repeated God''s special rules in chapter 5. What are these rules called?', 'The Beatitudes', 'The Ten Commandments', 'The Priestly Laws', 'The Feasts', 'a', 'Deuteronomy 5:6-21 — Moses restated the Ten Commandments given at Horeb.'),
('Deuteronomy', 5, 'kids', 2, 'On which day did God command Israel to rest and do no work?', 'The first day', 'The seventh day, the sabbath', 'The third day', 'The fifth day', 'a', 'Deuteronomy 5:14 — "The seventh day is the sabbath of the LORD thy God: in it thou shalt not do any work."'),
('Deuteronomy', 5, 'kids', 3, 'What did God write the Ten Commandments on when He first gave them at the mountain?', 'A scroll of papyrus', 'Two tablets of stone', 'A golden plate', 'The wall of the tabernacle', 'a', 'Deuteronomy 5:22 — "These words the LORD spake...and he wrote them in two tables of stone."'),
-- Teens
('Deuteronomy', 5, 'teens', 1, 'How does the Sabbath commandment in Deuteronomy 5 differ from the version in Exodus 20 in its reason for rest?', 'Deuteronomy adds servants to those who must rest', 'Deuteronomy grounds the Sabbath in the Exodus from Egypt rather than creation', 'Deuteronomy makes the Sabbath stricter by forbidding travel', 'Deuteronomy says foreigners are excluded from Sabbath rest', 'a', 'Deuteronomy 5:15 — "Remember that thou wast a servant in the land of Egypt...therefore the LORD thy God commanded thee to keep the sabbath day" — grounding it in redemption, not creation.'),
('Deuteronomy', 5, 'teens', 2, 'What was the people''s reaction when they heard God''s voice from the fire at Horeb?', 'They fell on their faces and praised God', 'They begged Moses to be their mediator so they would not die', 'They built an altar and sacrificed', 'They ran into the cloud and sought God''s face', 'a', 'Deuteronomy 5:25 — "Now therefore why should we die? for this great fire will consume us...if we hear the voice of the LORD our God any more, then we shall die."'),
('Deuteronomy', 5, 'teens', 3, 'What did God say about Israel''s desire to have a human mediator instead of hearing His voice directly?', 'He was displeased that they feared Him', 'He said they had done well and wished their hearts would always fear Him and keep His commandments', 'He told them they were unworthy of His presence', 'He appointed Moses as permanent high priest', 'a', 'Deuteronomy 5:28-29 — "They have well said all that they have spoken. O that there were such an heart in them, that they would fear me, and keep all my commandments always."'),
('Deuteronomy', 5, 'teens', 4, 'What commandment promises long life for those who keep it?', 'Keep the Sabbath', 'Honour thy father and thy mother', 'Thou shalt not kill', 'Thou shalt have no other gods', 'a', 'Deuteronomy 5:16 — "Honour thy father and thy mother...that thy days may be prolonged, and that it may go well with thee, in the land which the LORD thy God giveth thee."'),
('Deuteronomy', 5, 'teens', 5, 'What role did God assign Moses after the people asked him to be their mediator?', 'To build the tabernacle', 'To stand between God and Israel, hear all God says, and teach them', 'To write the laws on stone again', 'To lead the army into battle', 'a', 'Deuteronomy 5:31 — "But as for thee, stand thou here by me, and I will speak unto thee all the commandments...and thou shalt teach them."'),
-- Adults
('Deuteronomy', 5, 'adults', 1, 'What exact claim does Moses make about the Ten Commandments and the Sinai fire in verse 22?', 'God commanded them in an audible voice from a cloud', 'These words the LORD spake unto all your assembly out of the midst of the fire...with a great voice and he added no more, and wrote them in two tables', 'Moses received them alone on the mountain top', 'The elders of Israel also heard these words directly', 'a', 'Deuteronomy 5:22 — "These words the LORD spake unto all your assembly...with a great voice: and he added no more. And he wrote them in two tables of stone."'),
('Deuteronomy', 5, 'adults', 2, 'What theological phrase introduces the Ten Commandments in Deuteronomy 5:6?', 'I am the LORD thy God, who made heaven and earth', 'I am the LORD thy God, which brought thee out of the land of Egypt, from the house of bondage', 'I am the LORD, the God of thy fathers', 'I am the LORD thy God, the Holy One of Israel', 'a', 'Deuteronomy 5:6 — "I am the LORD thy God, which brought thee out of the land of Egypt, from the house of bondage."'),
('Deuteronomy', 5, 'adults', 3, 'The commandment against coveting in Deuteronomy 5 lists one item first that differs from the Exodus 20 version. What is it?', 'In Deuteronomy, the neighbour''s wife is listed before his house', 'In Deuteronomy, the neighbour''s field is added after his house', 'In Deuteronomy, the neighbour''s servant is listed first', 'In Deuteronomy, the list is shorter and ends with wife', 'a', 'Deuteronomy 5:21 — "Neither shalt thou desire thy neighbour''s wife, neither shalt thou covet thy neighbour''s house, his field..." — wife is listed first, then house and field.'),
('Deuteronomy', 5, 'adults', 4, 'What statement does Moses make about the audience in chapter 5 to emphasize the covenant''s immediacy?', 'Their fathers received this covenant at Sinai', 'The LORD made this covenant not with our fathers but with us who are all here alive this day', 'The covenant is for future generations only', 'The covenant was made once and cannot be renewed', 'a', 'Deuteronomy 5:3 — "The LORD made not this covenant with our fathers, but with us, even us, who are all of us here alive this day."'),
('Deuteronomy', 5, 'adults', 5, 'What physical phenomenon accompanied God''s speaking at Horeb, according to Deuteronomy 5?', 'Mighty earthquakes and floods', 'Fire, cloud, thick darkness, and a great voice', 'An earthquake and the mountain splitting', 'Lightning and the sound of many waters', 'a', 'Deuteronomy 5:22-23 — "Out of the midst of the fire, of the cloud, and of the thick darkness, with a great voice."'),
('Deuteronomy', 5, 'adults', 6, 'What were Moses'' responsibilities regarding the commandments that he received beyond the Ten?', 'He was to add his own interpretations', 'He was to teach them statutes and judgments which they should do in the land they were going to possess', 'He was to write them on the doorposts of the tabernacle', 'He was to deliver them to the priests only', 'a', 'Deuteronomy 5:31 — "I will speak unto thee all the commandments, and the statutes, and the judgments, which thou shalt teach them."'),
('Deuteronomy', 5, 'adults', 7, 'How does God describe His attitude toward those who love Him and keep His commandments in the second commandment''s preamble?', 'He is patient with them', 'Shewing mercy unto thousands of them that love me and keep my commandments', 'He will bless them above all peoples', 'He will give them wisdom and long life', 'a', 'Deuteronomy 5:10 — "And shewing mercy unto thousands of them that love me and keep my commandments."'),
('Deuteronomy', 5, 'adults', 8, 'God''s statement "I the LORD thy God am a jealous God" appears in which commandment context?', 'The fourth commandment concerning the Sabbath', 'The second commandment forbidding graven images', 'The first commandment concerning other gods', 'The fifth commandment concerning parents', 'a', 'Deuteronomy 5:9 — "Thou shalt not bow down thyself unto them, nor serve them: for I the LORD thy God am a jealous God."');

-- ═══ Deuteronomy Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 6, 'kids', 1, 'What is the famous verse that begins "Hear, O Israel: The LORD our God is one LORD"?', 'Deuteronomy 6:1', 'Deuteronomy 6:4', 'Deuteronomy 6:10', 'Deuteronomy 6:13', 'a', 'Deuteronomy 6:4 — "Hear, O Israel: The LORD our God is one LORD." This verse is called the Shema.'),
('Deuteronomy', 6, 'kids', 2, 'God told Israel to write His commandments on two special places in their homes. Where were they?', 'On the walls and the floor', 'On their doorposts and gates', 'On their beds and tables', 'On the ceiling and the door', 'a', 'Deuteronomy 6:9 — "And thou shalt write them upon the posts of thy house, and on thy gates."'),
('Deuteronomy', 6, 'kids', 3, 'How much did God say Israel should love the LORD?', 'A little bit, when they have time', 'With all thine heart, soul, and might', 'More than their family', 'Only on holy days', 'a', 'Deuteronomy 6:5 — "And thou shalt love the LORD thy God with all thine heart, and with all thy soul, and with all thy might."'),
-- Teens
('Deuteronomy', 6, 'teens', 1, 'What is the Hebrew term for the prayer that begins "Hear, O Israel" in Deuteronomy 6:4-9?', 'The Hallel', 'The Shema', 'The Amidah', 'The Kiddush', 'a', 'Deuteronomy 6:4 — "Hear, O Israel: The LORD our God is one LORD" — this passage is known as the Shema, from the Hebrew word for "hear."'),
('Deuteronomy', 6, 'teens', 2, 'Moses warned Israel about forgetting God when they prospered in the land. What specific temptation did he name?', 'Fighting against neighbouring nations', 'Eating and being full, building houses, and saying in thine heart My power hath gotten me this wealth', 'Intermarrying with Canaanites', 'Refusing to bring tithes to the priests', 'a', 'Deuteronomy 6:11-12 — "When thou shalt have eaten and be full...then beware lest thou forget the LORD."'),
('Deuteronomy', 6, 'teens', 3, 'What instruction did Moses give for parents when their children ask the meaning of the commandments?', 'Send them to a priest for instruction', 'Say unto them, We were Pharaoh''s bondmen in Egypt and the LORD brought us out', 'Tell them to read the law themselves', 'Bring them to the tabernacle for teaching', 'a', 'Deuteronomy 6:20-21 — "And when thy son asketh thee in time to come...thou shalt say unto thy son, We were Pharaoh''s bondmen in Egypt."'),
('Deuteronomy', 6, 'teens', 4, 'What warning did Moses give about testing the LORD their God?', 'They should test Him only in cases of great need', 'Ye shall not tempt the LORD your God, as ye tempted him in Massah', 'Testing God was reserved for priests only', 'Testing was permitted in times of war', 'a', 'Deuteronomy 6:16 — "Ye shall not tempt the LORD your God, as ye tempted him in Massah."'),
('Deuteronomy', 6, 'teens', 5, 'How did Moses describe the purpose of the commandments regarding Israel''s righteousness before God?', 'The commandments made Israel greater than all nations', 'It shall be our righteousness if we observe to do all these commandments before the LORD', 'Keeping commandments earned Israel military victories', 'The commandments were Israel''s gift back to God', 'a', 'Deuteronomy 6:25 — "And it shall be our righteousness, if we observe to do all these commandments before the LORD our God, as he hath commanded us."'),
-- Adults
('Deuteronomy', 6, 'adults', 1, 'What threefold purpose does Moses give for the commandments at the opening of chapter 6?', 'To make Israel wealthy, wise, and warlike', 'That they might fear the LORD, keep His statutes, and that their days may be prolonged', 'To set Israel apart from all nations permanently', 'To prepare Israel for priestly service', 'a', 'Deuteronomy 6:2 — "That thou mightest fear the LORD thy God, to keep all his statutes and his commandments...that thy days may be prolonged."'),
('Deuteronomy', 6, 'adults', 2, 'The command to bind God''s words "as a sign upon thine hand" and as "frontlets between thine eyes" in Deuteronomy 6:8 is the basis for which Jewish practice?', 'Mezuzot on doorposts', 'Tefillin (phylacteries)', 'Tzitzit on garments', 'Wearing the priestly breastplate', 'a', 'Deuteronomy 6:8 — "And thou shalt bind them for a sign upon thine hand, and they shall be as frontlets between thine eyes" — the basis of tefillin.'),
('Deuteronomy', 6, 'adults', 3, 'In what context does Jesus quote Deuteronomy 6:5 in the New Testament?', 'When healing a blind man', 'When answering which is the great commandment of the law', 'In the Sermon on the Mount', 'When cleansing the temple', 'a', 'Deuteronomy 6:5 — "Thou shalt love the LORD thy God with all thine heart" — Jesus quotes this as the greatest commandment in Matthew 22:37.'),
('Deuteronomy', 6, 'adults', 4, 'What diligent teaching practice does Moses prescribe for transmitting the commandments to children?', 'Weekly recitation in the assembly', 'Thou shalt teach them diligently unto thy children, and shalt talk of them when thou sittest in thine house, and when thou walkest by the way, and when thou liest down, and when thou risest up', 'Annual reading at the Passover feast', 'Having the Levites instruct each family', 'a', 'Deuteronomy 6:7 — "And thou shalt teach them diligently unto thy children, and shalt talk of them when thou sittest in thine house."'),
('Deuteronomy', 6, 'adults', 5, 'What specific danger does Moses highlight about the prosperity Israel will find in Canaan''s already-built cities?', 'Israel might become too proud to fight', 'Lest thou forget the LORD which brought thee forth out of the land of Egypt, from the house of bondage', 'The Canaanites might reclaim their houses', 'Israel might not know how to farm the land', 'a', 'Deuteronomy 6:10-12 — "When the LORD thy God shall have brought thee into the land...beware lest thou forget the LORD."'),
('Deuteronomy', 6, 'adults', 6, 'God promises to drive out which nations before Israel according to chapter 6?', 'Seven nations: the Hittite, Girgashite, Amorite, Canaanite, Perizzite, Hivite, and Jebusite', 'Three nations: the Canaanites, Philistines, and Hittites', 'All twelve tribes remaining in the land', 'Five nations: Midian, Moab, Ammon, Edom, and Canaan', 'a', 'Deuteronomy 7:1 (immediately following ch 6) enumerates "seven nations greater and mightier than thou"; in ch 6 Moses anticipates this by warning against their gods.'),
('Deuteronomy', 6, 'adults', 7, 'What does Moses command Israel to do with the commandments they are to love and obey?', 'Engrave them only on the tabernacle furnishings', 'These words shall be in thine heart — to teach, bind, write on posts and gates', 'Recite them only on the Sabbath', 'Keep them in the ark of the covenant', 'a', 'Deuteronomy 6:6-9 — "These words...shall be in thine heart...teach them...talk of them...bind them...write them upon the posts."'),
('Deuteronomy', 6, 'adults', 8, 'What does Moses say Israel''s diligent keeping of God''s commandments will produce as a final outcome?', 'They will become the wealthiest nation on earth', 'It will be righteousness unto them if they observe to do all these commandments', 'Their army will be unconquerable', 'They will receive a new covenant with greater promises', 'a', 'Deuteronomy 6:25 — "And it shall be our righteousness, if we observe to do all these commandments before the LORD our God."');

-- ═══ Deuteronomy Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 7, 'kids', 1, 'God commanded Israel not to marry the people of which lands they were entering?', 'Egypt and Babylon', 'The seven Canaanite nations', 'Moab and Ammon only', 'Edom and Midian', 'a', 'Deuteronomy 7:1-3 — "When the LORD thy God shall bring thee into the land...thou shalt make no marriages with them."'),
('Deuteronomy', 7, 'kids', 2, 'Why did God choose Israel to be His special people?', 'Because they were the biggest nation', 'Not because they were many but because God loved them and kept His oath to the fathers', 'Because they were the cleverest people', 'Because they had the best soldiers', 'a', 'Deuteronomy 7:6-8 — "The LORD did not set his love upon you, nor choose you, because ye were more in number...but because the LORD loved you."'),
('Deuteronomy', 7, 'kids', 3, 'What were Israel supposed to destroy when they conquered the Canaanite nations?', 'Only their armies', 'Their altars, images, groves, and graven images', 'Their food and livestock', 'Their cities and houses', 'a', 'Deuteronomy 7:5 — "But thus shall ye deal with them; ye shall destroy their altars, and break down their images, and cut down their groves, and burn their graven images."'),
-- Teens
('Deuteronomy', 7, 'teens', 1, 'What does Moses mean by calling Israel "an holy people" and "a peculiar people" unto the LORD?', 'Israel was strange compared to other nations', 'Israel was set apart and specially treasured as God''s own possession above all people on earth', 'Israel had unusual customs that made them different', 'Israel was forbidden from all contact with foreigners', 'a', 'Deuteronomy 7:6 — "For thou art an holy people unto the LORD thy God: the LORD thy God hath chosen thee to be a special people unto himself, above all people that are upon the face of the earth."'),
('Deuteronomy', 7, 'teens', 2, 'How did God describe His faithfulness to those who love Him and keep His commandments?', 'He would keep covenant and mercy for a thousand generations', 'He would give them victory in every battle', 'He would multiply their cattle and harvests', 'He would let them live forever', 'a', 'Deuteronomy 7:9 — "Know therefore that the LORD thy God, he is God, the faithful God, which keepeth covenant and mercy with them that love him and keep his commandments to a thousand generations."'),
('Deuteronomy', 7, 'teens', 3, 'What would happen to those who hated God according to verse 10?', 'They would be enslaved', 'He would repay them that hate him to their face to destroy them', 'They would be banished from the land', 'They would lose their prosperity', 'a', 'Deuteronomy 7:10 — "And repayeth them that hate him to their face, to destroy them: he will not be slack to him that hateth him."'),
('Deuteronomy', 7, 'teens', 4, 'What strategy did God say He would use against the Canaanites — not all at once but little by little, and why?', 'Because Israel''s army was still small', 'Lest the beast of the field increase upon thee', 'Because the cities needed to be inspected first', 'Because Israel needed time to learn farming', 'a', 'Deuteronomy 7:22 — "The LORD thy God will put out those nations before thee by little and little: thou mayest not consume them at once, lest the beasts of the field increase upon thee."'),
('Deuteronomy', 7, 'teens', 5, 'What did Moses tell Israel to do with the silver and gold on the Canaanite idols?', 'Melt it down for the tabernacle', 'Not desire it nor take it, for it was an abomination', 'Give it to the Levites', 'Bury it in the ground', 'a', 'Deuteronomy 7:25 — "Thou shalt not desire the silver or gold that is on them, nor take it unto thee, lest thou be snared therein: for it is an abomination to the LORD thy God."'),
-- Adults
('Deuteronomy', 7, 'adults', 1, 'What is the Hebrew concept behind the command to "utterly destroy" the Canaanite nations, and what term is used in later scholarship for this practice?', 'Complete annihilation called jihad', 'The concept of cherem — total consecration/destruction to the LORD', 'A military strategy called scorched earth', 'A purification ritual called kiddush', 'a', 'Deuteronomy 7:2 — "And when the LORD thy God shall deliver them before thee; thou shalt smite them, and utterly destroy them" — the Hebrew cherem implies total devotion to God through destruction.'),
('Deuteronomy', 7, 'adults', 2, 'What specific covenantal act does Moses forbid Israel from making with the seven nations, and what is the explicitly stated reason?', 'No trade agreements, lest they become economically dependent', 'No covenants or showing mercy, for they would turn Israel from following the LORD to serve other gods', 'No intermarriage only, to preserve the genetic line', 'No military alliances, because God would fight for Israel alone', 'a', 'Deuteronomy 7:2-4 — "Thou shalt make no covenant with them...neither shalt thou make marriages with them...for they will turn away thy son from following me."'),
('Deuteronomy', 7, 'adults', 3, 'How does Moses describe the blessing that will follow obedience in the land in verses 13-15?', 'Israel will rule all nations as a superpower', 'The LORD will love, bless, and multiply thee — blessing fruit of womb, land, grain, wine, oil, cattle — and remove all sickness', 'Israel will receive tribute from all surrounding kingdoms', 'The land will yield harvests a hundredfold', 'a', 'Deuteronomy 7:13-15 — "He will love thee, and bless thee, and multiply thee...he will also bless the fruit of thy womb...and the LORD will take away from thee all sickness."'),
('Deuteronomy', 7, 'adults', 4, 'What theological reason does Moses give for Israel not fearing the more numerous Canaanite nations?', 'Israel had better weapons', 'Remember what the LORD did unto Pharaoh and unto Egypt — the same mighty hand and outstretched arm would deliver', 'Angels would precede Israel into battle', 'The Canaanites'' gods could not help them', 'a', 'Deuteronomy 7:18-19 — "Thou shalt not be afraid of them: but shalt well remember what the LORD thy God did unto Pharaoh, and unto all Egypt."'),
('Deuteronomy', 7, 'adults', 5, 'Moses promises God will send the hornet before Israel. What is the significance of this sign?', 'It represents God''s sting of judgment on the wicked', 'God would use natural means as well as supernatural to drive out the nations before Israel arrived', 'The hornet was the symbol of Egypt and would terrorize the Canaanites', 'It was a literal plague of insects that weakened the Canaanites', 'a', 'Deuteronomy 7:20 — "Moreover the LORD thy God will send the hornet among them, until they that are left, and hide themselves from thee, be destroyed."'),
('Deuteronomy', 7, 'adults', 6, 'What promise does God make about His own power in relation to the nations that appear greater and mightier than Israel?', 'God will weaken them with disease before battle', 'The LORD thy God is among you, a mighty God and terrible', 'God will confuse the nations with strange languages', 'God will send fire from heaven on their cities', 'a', 'Deuteronomy 7:21 — "Thou shalt not be affrighted at them: for the LORD thy God is among you, a mighty God and terrible."'),
('Deuteronomy', 7, 'adults', 7, 'The covenant faithfulness of God in Deuteronomy 7 spans "a thousand generations." What does this communicate about the nature of God''s covenant love?', 'The covenant will expire after a thousand generations', 'Divine hesed (covenant mercy/love) is immeasurably greater in duration than human generations', 'God calculated exactly how many generations Israel would last', 'The covenant was mainly for ancient Israelites', 'a', 'Deuteronomy 7:9 — "keepeth covenant and mercy with them that love him...to a thousand generations" — expressing infinite divine faithfulness.'),
('Deuteronomy', 7, 'adults', 8, 'How does Moses describe the Canaanite idols in terms of their ultimate fate and the fate of anyone who is attracted to them?', 'They are valueless curiosities to be ignored', 'They are an abomination and a snare, and the detestable thing must be utterly abhorred and abominated', 'They are tempting but powerless', 'They may be kept as trophies of victory', 'a', 'Deuteronomy 7:25-26 — "Thou shalt not bring an abomination into thine house...but thou shalt utterly detest it, and thou shalt utterly abhor it; for it is a cursed thing."');

-- ═══ Deuteronomy Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 8, 'kids', 1, 'What special food did God give Israel to eat in the wilderness that they had never seen before?', 'Bread from heaven called manna', 'Fruit from magical trees', 'Fish from the desert springs', 'Sweet berries from the rocks', 'a', 'Deuteronomy 8:3 — "He...suffered thee to hunger, and fed thee with manna, which thou knewest not, neither did thy fathers know."'),
('Deuteronomy', 8, 'kids', 2, 'Moses said man does not live by bread alone but by what?', 'Every good thought', 'Every word that proceedeth out of the mouth of God', 'The water from the rock', 'Every commandment of Moses', 'a', 'Deuteronomy 8:3 — "Man doth not live by bread only, but by every word that proceedeth out of the mouth of the LORD doth man live."'),
('Deuteronomy', 8, 'kids', 3, 'What miracle happened to Israel''s clothes and feet during forty years in the wilderness?', 'New clothes appeared each morning', 'Their clothes did not wear out and their feet did not swell', 'God gave them shoes made of iron', 'Their sandals grew back when broken', 'a', 'Deuteronomy 8:4 — "Thy raiment waxed not old upon thee, neither did thy foot swell, these forty years."'),
-- Teens
('Deuteronomy', 8, 'teens', 1, 'What was the stated purpose of God humbling Israel and letting them hunger in the wilderness?', 'To punish them for the golden calf', 'To prove what was in their heart, whether they would keep his commandments or not', 'To show the surrounding nations God''s power', 'To teach them to depend on priests for food', 'a', 'Deuteronomy 8:2 — "To humble thee, and to prove thee, to know what was in thine heart, whether thou wouldest keep his commandments, or no."'),
('Deuteronomy', 8, 'teens', 2, 'Moses described the promised land as "a good land." What bodies of water did he say it had?', 'Great rivers like the Nile and Euphrates', 'Brooks of water, of fountains and depths that spring out of valleys and hills', 'A great sea on every side', 'Vast underground lakes', 'a', 'Deuteronomy 8:7 — "A land of brooks of water, of fountains and depths that spring out of valleys and hills."'),
('Deuteronomy', 8, 'teens', 3, 'What were Israel supposed to do after eating and being satisfied in the good land?', 'Build temples on the hilltops', 'Bless the LORD their God for the good land he had given them', 'Offer the firstfruits to Moses', 'Plant more of the crops they had harvested', 'a', 'Deuteronomy 8:10 — "When thou hast eaten and art full, then thou shalt bless the LORD thy God for the good land which he hath given thee."'),
('Deuteronomy', 8, 'teens', 4, 'What dangerous attitude did Moses warn Israel against when they became prosperous and wealthy?', 'Forgetting the Sabbath', 'Saying in their heart, My power and the might of mine hand hath gotten me this wealth', 'Refusing to go to war', 'Building too large a city', 'a', 'Deuteronomy 8:17 — "And thou say in thine heart, My power and the might of mine hand hath gotten me this wealth."'),
('Deuteronomy', 8, 'teens', 5, 'What consequence did Moses say would come if Israel forgot the LORD and followed other gods?', 'They would lose only their wealth', 'Ye shall surely perish, as the nations whom the LORD destroyeth before your face', 'Their crops would fail for one season', 'They would lose only their military power', 'a', 'Deuteronomy 8:19-20 — "If thou do at all forget the LORD thy God...ye shall surely perish, as the nations which the LORD destroyeth before your face."'),
-- Adults
('Deuteronomy', 8, 'adults', 1, 'Jesus quotes Deuteronomy 8:3 in response to which temptation in the wilderness?', 'The temptation to cast himself from the temple', 'The temptation to turn stones into bread', 'The temptation to bow to Satan', 'The temptation to call angels for help', 'a', 'Deuteronomy 8:3 — "Man doth not live by bread only, but by every word that proceedeth out of the mouth of the LORD" — quoted in Matthew 4:4.'),
('Deuteronomy', 8, 'adults', 2, 'What relationship does Moses draw between the fatherly discipline of a man and God''s discipline of Israel?', 'As a teacher disciplines a student for knowledge', 'As a man chasteneth his son, so the LORD thy God chasteneth thee', 'As a king disciplines a subject for rebellion', 'As a shepherd corrects a wayward sheep', 'a', 'Deuteronomy 8:5 — "Thou shalt also consider in thine heart, that, as a man chasteneth his son, so the LORD thy God chasteneth thee."'),
('Deuteronomy', 8, 'adults', 3, 'The "good land" described in Deuteronomy 8 includes what mineral resources, demonstrating its material abundance?', 'Gold and silver in great quantity', 'A land whose stones are iron, and out of whose hills thou mayest dig brass', 'Precious gems in the rivers and hills', 'Salt mines and sulfur springs', 'a', 'Deuteronomy 8:9 — "A land whose stones are iron, and out of whose hills thou mayest dig brass."'),
('Deuteronomy', 8, 'adults', 4, 'What seven agricultural products describe the fertility of the promised land in Deuteronomy 8:8?', 'Wheat, barley, figs, olives, dates, flax, and flint', 'Wheat, barley, vines, fig trees, pomegranates, olive trees, and honey', 'Wheat, millet, corn, grapes, almonds, walnuts, and dates', 'Barley, rye, spelt, grapes, olives, flax, and leeks', 'a', 'Deuteronomy 8:8 — "A land of wheat, and barley, and vines, and fig trees, and pomegranates; a land of oil olive, and honey."'),
('Deuteronomy', 8, 'adults', 5, 'What specific cognitive and spiritual danger does Moses associate with material prosperity in chapter 8?', 'Pride in personal achievement that leads to forgetting divine grace', 'Lest when thou hast eaten and art full...thine heart be lifted up, and thou forget the LORD', 'Addiction to luxury that prevents prayer', 'Satisfying physical needs at the expense of spiritual disciplines', 'a', 'Deuteronomy 8:12-14 — "Lest when thou hast eaten and art full...thine heart be lifted up, and thou forget the LORD thy God."'),
('Deuteronomy', 8, 'adults', 6, 'What rhetorical correction does Moses offer to the temptation toward self-sufficiency in verse 17?', 'That Israel''s wealth was borrowed from God', 'But thou shalt remember the LORD thy God: for it is he that giveth thee power to get wealth', 'That God could take the wealth away at any moment', 'That Moses was the true source of Israel''s blessings', 'a', 'Deuteronomy 8:18 — "But thou shalt remember the LORD thy God: for it is he that giveth thee power to get wealth."'),
('Deuteronomy', 8, 'adults', 7, 'How does Moses describe the wilderness in chapter 8 to contrast God''s miraculous provision with natural scarcity?', 'A dry and thirsty land with no water', 'That great and terrible wilderness, wherein were fiery serpents, and scorpions, and drought', 'A land of thorns and thistles and constant danger', 'A vast empty desert with no food or shelter', 'a', 'Deuteronomy 8:15 — "Who led thee through that great and terrible wilderness, wherein were fiery serpents, and scorpions, and drought."'),
('Deuteronomy', 8, 'adults', 8, 'What covenantal purpose does God''s provision of wealth connect to, according to verse 18''s conclusion?', 'To make Israel an example to Gentile nations', 'That he may establish his covenant which he sware unto thy fathers', 'To prove Israel is more righteous than the nations', 'To prepare Israel for the coming of a messianic king', 'a', 'Deuteronomy 8:18 — "It is he that giveth thee power to get wealth, that he may establish his covenant which he sware unto thy fathers."');

-- ═══ Deuteronomy Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 9, 'kids', 1, 'What did Israel do with a golden animal while Moses was on the mountain with God?', 'They built a golden lion', 'They made a golden calf', 'They carved a golden eagle', 'They melted gold into a serpent', 'a', 'Deuteronomy 9:16 — "And I looked, and, behold, ye had sinned against the LORD your God, and had made you a molten calf."'),
('Deuteronomy', 9, 'kids', 2, 'How many days and nights did Moses stay on the mountain without eating or drinking?', 'Seven days and nights', 'Forty days and forty nights', 'Twenty days and nights', 'Three days and nights', 'a', 'Deuteronomy 9:9 — "I abode in the mount forty days and forty nights, I neither did eat bread nor drink water."'),
('Deuteronomy', 9, 'kids', 3, 'Moses told Israel they were not getting the promised land because they were better than the Canaanites. Was this true?', 'Yes, Israel was much better', 'No, it was because of the Canaanites'' wickedness and God''s promise to the fathers', 'Yes, because Israel obeyed all of God''s laws', 'No, Moses said they were too small a nation', 'a', 'Deuteronomy 9:4-5 — "Speak not thou in thine heart...Not for thy righteousness...but for the wickedness of these nations...and that he may perform the word which the LORD sware unto thy fathers."'),
-- Teens
('Deuteronomy', 9, 'teens', 1, 'What did Moses say about Israel''s character at the very beginning of chapter 9 to set up his warning?', 'Thou art a holy and obedient people', 'Thou art to pass over Jordan to possess nations greater than thee, whose cities are great and walled up to heaven', 'Thou art a strong and mighty nation', 'Thou art beloved among all peoples on earth', 'a', 'Deuteronomy 9:1 — "Hear, O Israel: Thou art to pass over Jordan this day, to go in to possess nations greater and mightier than thyself, cities great and fenced up to heaven."'),
('Deuteronomy', 9, 'teens', 2, 'Moses listed multiple times Israel had provoked the LORD. Name two of the rebellions he recalled.', 'Crossing the Red Sea and camping at Sinai', 'The golden calf at Horeb, the rebellion at Taberah, Massah, Kibroth-hattaavah, and Kadesh-barnea', 'The complaints about manna and the attack on Amalek', 'The rebellion of Korah and the incident at Baal-peor', 'a', 'Deuteronomy 9:22-23 — "And at Taberah, and at Massah, and at Kibroth-hattaavah, ye provoked the LORD to wrath...Also in Kadesh-barnea ye rebelled."'),
('Deuteronomy', 9, 'teens', 3, 'What drastic action did Moses take with the two tablets when he came down and saw the golden calf?', 'He hid them in the ark', 'He cast them out of his two hands and brake them before their eyes', 'He raised them above his head and called Israel to repent', 'He gave them to the priests for safekeeping', 'a', 'Deuteronomy 9:17 — "And I took the two tables, and cast them out of my two hands, and brake them before your eyes."'),
('Deuteronomy', 9, 'teens', 4, 'How did Moses destroy the golden calf?', 'He melted it and threw it in the river', 'He burnt it with fire, beat it to dust, and cast the dust into the brook', 'He buried it in the ground outside the camp', 'He commanded the Levites to carry it away', 'a', 'Deuteronomy 9:21 — "And I took your sin, the calf which ye had made, and burnt it with fire, and stamped it, and ground it very small, even until it was as small as dust: and I cast the dust thereof into the brook."'),
('Deuteronomy', 9, 'teens', 5, 'For whom did Moses pray during his forty days of intercession, according to the end of chapter 9?', 'For himself that he might enter the land', 'For Aaron whom the LORD was also angry with, and for all Israel', 'For the Levites who did not sin', 'For the next generation who would inherit the land', 'a', 'Deuteronomy 9:20 — "And the LORD was very angry with Aaron to have destroyed him: and I prayed for Aaron also at the same time."'),
-- Adults
('Deuteronomy', 9, 'adults', 1, 'What theological principle does Moses establish in Deuteronomy 9:4-6 that is foundational for understanding grace?', 'That righteousness is measured by obedience to law', 'That Israel''s possession of the land was not due to their righteousness but to God''s grace and the nations'' wickedness', 'That God rewards military courage above all virtues', 'That national prosperity comes from inherited merit', 'a', 'Deuteronomy 9:4-5 — "Not for thy righteousness, or for the uprightness of thine heart, dost thou go to possess their land: but for the wickedness of these nations."'),
('Deuteronomy', 9, 'adults', 2, 'Moses describes Israel as a "stiffnecked people" in chapter 9. What does this agricultural metaphor convey?', 'That Israel worked hard like oxen', 'That like an ox that will not submit to the yoke, Israel was stubbornly resistant to God''s direction', 'That Israel''s priests were too rigid in their interpretations', 'That Israel was physically strong but spiritually lazy', 'a', 'Deuteronomy 9:6 — "Understand therefore, that the LORD thy God giveth thee not this good land for thy righteousness; for thou art a stiffnecked people."'),
('Deuteronomy', 9, 'adults', 3, 'What was God''s stated intention after the golden calf, and how did Moses intercede against it?', 'God intended to scatter Israel and Moses prayed for mercy', 'God said He would destroy Israel and make of Moses a nation, but Moses prostrated himself forty days praying for Israel', 'God intended to send Israel back to Egypt and Moses argued this would shame God before Pharaoh', 'God intended to give the land to Caleb only and Moses argued for all twelve tribes', 'a', 'Deuteronomy 9:14,18 — "Let me alone, that I may destroy them...And I fell down before the LORD...forty days and forty nights."'),
('Deuteronomy', 9, 'adults', 4, 'Moses bases his intercessory prayer on several arguments. What is the primary theological argument he uses in chapter 9?', 'That Israel had suffered enough in Egypt already', 'That God should spare Israel lest the land from which He brought them say He brought them out to destroy them', 'That the patriarchs had been perfectly righteous', 'That the younger generation had not sinned', 'a', 'Deuteronomy 9:28 — "Lest the land whence thou broughtest us out say, Because the LORD was not able to bring them into the land...he hath brought them out to slay them."'),
('Deuteronomy', 9, 'adults', 5, 'What does Moses'' second forty-day fast on the mountain accomplish according to the narrative?', 'God writes new commandments broader than the first', 'God hears Moses and agrees not to destroy Israel, preparing for new tablets', 'Moses receives the blueprints for the tabernacle', 'God lifts the curse of wandering and promises immediate entry to Canaan', 'a', 'Deuteronomy 9:18-19 — "And I fell down before the LORD...and the LORD hearkened unto me at that time also."'),
('Deuteronomy', 9, 'adults', 6, 'How does Moses describe the Anakims in chapter 9 in terms of their military reputation?', 'As skilled archers feared throughout Canaan', 'As sons of the Anakims — tall and dreadful — of whom Israel had heard: Who can stand before the children of Anak?', 'As a people protected by powerful magic', 'As chariot warriors superior to any in Egypt', 'a', 'Deuteronomy 9:2 — "A people great and tall, the children of the Anakims, whom thou knowest, and of whom thou hast heard say, Who can stand before the children of Anak!"'),
('Deuteronomy', 9, 'adults', 7, 'What does the phrase "from the day thou didst depart out of the land of Egypt" in verse 7 communicate about Israel''s track record?', 'Israel had been mostly obedient with occasional failures', 'Israel had been provoking the LORD to wrath continuously from departure out of Egypt until that very day', 'Israel had improved significantly after the wilderness years', 'Israel had been faithful in Egypt but rebellious only in the wilderness', 'a', 'Deuteronomy 9:7 — "Remember, and forget not, how thou provokedst the LORD thy God to wrath in the wilderness: from the day that thou didst depart out of the land of Egypt, until ye came unto this place, ye have been rebellious against the LORD."'),
('Deuteronomy', 9, 'adults', 8, 'Moses'' appeal to "thy servants Abraham, Isaac, and Jacob" in his prayer establishes what hermeneutical principle for understanding divine faithfulness?', 'That the patriarchs'' merits transfer to their descendants', 'That God''s covenantal promises made to the fathers are irrevocable and form the ground of mercy for their descendants', 'That intercessory prayer must always invoke ancestral precedents', 'That God favors those with famous relatives', 'a', 'Deuteronomy 9:27 — "Remember thy servants, Abraham, Isaac, and Jacob; look not unto the stubbornness of this people, nor to their wickedness, nor to their sin."');

-- ═══ Deuteronomy Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Deuteronomy', 10, 'kids', 1, 'God told Moses to make a special box to keep the stone tablets in. What was it called?', 'The golden chest', 'The ark of wood', 'The sacred vessel', 'The covenant box', 'a', 'Deuteronomy 10:1-2 — "Hew thee two tables of stone...and make thee an ark of wood...and I will write on the tables the words that were in the first tables."'),
('Deuteronomy', 10, 'kids', 2, 'God told Israel to love and care for which group of needy people, just as He cares for them?', 'The elderly and the sick', 'The stranger, the fatherless, and the widow', 'The poor in Israel only', 'The children of the Levites', 'a', 'Deuteronomy 10:18-19 — "He doth execute the judgment of the fatherless and widow, and loveth the stranger...Love ye therefore the stranger."'),
('Deuteronomy', 10, 'kids', 3, 'Moses said God was "God of gods" and "Lord of lords." What did he say about the size of the LORD?', 'God was as mighty as all the armies of the earth', 'God was a great God, a mighty, and a terrible, which regardeth not persons', 'God was as high as the tallest mountain', 'God was as wide as the seas', 'a', 'Deuteronomy 10:17 — "For the LORD your God is God of gods, and Lord of lords, a great God, a mighty, and a terrible, which regardeth not persons, nor taketh reward."'),
-- Teens
('Deuteronomy', 10, 'teens', 1, 'What did God ask of Israel in Deuteronomy 10:12, summarizing the entire law in a few words?', 'To build Him a temple and bring sacrifices daily', 'To fear the LORD, walk in all his ways, love him, serve him with all heart and soul, and keep his commandments', 'To defeat all their enemies and possess the land', 'To teach their children the law and keep the Sabbath', 'a', 'Deuteronomy 10:12 — "What doth the LORD thy God require of thee, but to fear the LORD thy God, to walk in all his ways, and to love him, and to serve the LORD thy God with all thy heart and with all thy soul."'),
('Deuteronomy', 10, 'teens', 2, 'What does Moses mean by "circumcise therefore the foreskin of your heart" in Deuteronomy 10:16?', 'Undergo a new physical ceremony', 'Remove spiritual stubbornness and pride — surrender the inner self to God', 'Cut away contact with foreign nations', 'Adopt a new form of worship', 'a', 'Deuteronomy 10:16 — "Circumcise therefore the foreskin of your heart, and be no more stiffnecked."'),
('Deuteronomy', 10, 'teens', 3, 'What tribe did God set apart for special sacred service with no land inheritance among the tribes?', 'The tribe of Judah', 'The tribe of Levi', 'The tribe of Reuben', 'The tribe of Joseph', 'a', 'Deuteronomy 10:8-9 — "At that time the LORD separated the tribe of Levi, to bear the ark...The LORD is his inheritance."'),
('Deuteronomy', 10, 'teens', 4, 'When Moses went back up the mountain for the second time, what did God command him to bring?', 'Offerings of gold and silver', 'Two tables of stone like the first and come up unto the LORD', 'The elders of Israel', 'The ark of the covenant', 'a', 'Deuteronomy 10:1 — "At that time the LORD said unto me, Hew thee two tables of stone like unto the first, and come up unto me into the mount."'),
('Deuteronomy', 10, 'teens', 5, 'Moses reminded Israel of how many people went down into Egypt with Jacob?', 'Seventy souls', 'One hundred and twenty souls', 'Forty souls', 'Two hundred souls', 'a', 'Deuteronomy 10:22 — "Thy fathers went down into Egypt with threescore and ten persons; and now the LORD thy God hath made thee as the stars of heaven for multitude."'),
-- Adults
('Deuteronomy', 10, 'adults', 1, 'What are the four specific duties of the Levites listed in Deuteronomy 10:8?', 'To teach the law, collect tithes, offer sacrifices, and judge cases', 'To bear the ark of the covenant, to stand before the LORD to minister, to bless in his name, and these functions continue to Moses'' day', 'To guard the tabernacle, lead worship, instruct the people, and arbitrate disputes', 'To offer burnt offerings, perform the Passover, maintain the tabernacle, and sound the trumpets', 'a', 'Deuteronomy 10:8 — "The LORD separated the tribe of Levi...to bear the ark of the covenant of the LORD, to stand before the LORD to minister unto him, and to bless in his name."'),
('Deuteronomy', 10, 'adults', 2, 'What is the significance of God saying "the heaven and the heaven of heavens" belong to Him in verse 14, in the context of His choosing Israel?', 'God owns the cosmos yet sovereignly condescended to delight in Israel''s fathers and their descendants above all nations', 'God is reminding Israel that He controls the weather and harvests', 'God is warning Israel that angels watch their behaviour from heaven', 'God is contrasting heavenly permanence with earthly transience', 'a', 'Deuteronomy 10:14-15 — "Behold, the heaven and the heaven of heavens is the LORD''s...Only the LORD had a delight in thy fathers to love them."'),
('Deuteronomy', 10, 'adults', 3, 'What specific attributes of God''s impartiality does Moses cite in verse 17, and how does this ground the command to care for the stranger?', 'God is omniscient and sees all injustice, therefore Israel must be just', 'God regardeth not persons nor taketh reward — He executes justice for fatherless and widow and loves the stranger — therefore Israel, once strangers in Egypt, must love the stranger', 'God is holy and Israel must be holy as He is holy', 'God is merciful and Israel must show mercy to all peoples', 'a', 'Deuteronomy 10:17-19 — "God...regardeth not persons...he doth execute the judgment of the fatherless and widow, and loveth the stranger...Love ye therefore the stranger: for ye were strangers in the land of Egypt."'),
('Deuteronomy', 10, 'adults', 4, 'The command to "cleave unto him" in verse 20 uses the same Hebrew verb (dabaq) as Genesis 2:24''s marriage union. What does this imply about Israel''s covenant relationship?', 'That covenant loyalty to God is modelled on the intimacy and permanence of marriage', 'That God and Israel are literally married in a legal sense', 'That breaking the covenant is like adultery', 'That the patriarchs were priests who mediated God''s presence like a husband', 'a', 'Deuteronomy 10:20 — "Thou shalt fear the LORD thy God; him shalt thou serve, and to him shalt thou cleave" — the verb cleave (dabaq) echoes the marital bond of Genesis 2:24.'),
('Deuteronomy', 10, 'adults', 5, 'What location is given as the place where Aaron died in chapter 10?', 'At the waters of Meribah', 'At Mosera', 'On Mount Hor', 'At Kadesh-barnea', 'a', 'Deuteronomy 10:6 — "And the children of Israel took their journey from Beeroth of the children of Jaakan to Mosera: there Aaron died, and there he was buried."'),
('Deuteronomy', 10, 'adults', 6, 'What phrase does Moses use in verse 21 to describe God''s deeds, connecting back to the Exodus and forward to Israel''s testimony?', 'He is thy praise, and he is thy God, that hath done for thee these great and terrible things which thine eyes have seen', 'He is the God of gods who made heaven and earth in six days', 'He is the LORD of hosts who fights all Israel''s battles', 'He is the eternal One who changes not from generation to generation', 'a', 'Deuteronomy 10:21 — "He is thy praise, and he is thy God, that hath done for thee these great and terrible things, which thine eyes have seen."'),
('Deuteronomy', 10, 'adults', 7, 'Moses transitions from recounting Israel''s failures in chapter 9 to summarizing the covenant demands in chapter 10:12-13. What does this structural move communicate about the relationship between grace and obedience?', 'Obedience earns God''s forgiveness for past sins', 'God''s patient forgiveness (ch 9) is the basis and motivation for wholehearted obedience (ch 10:12-13)', 'Moses was trying to frighten Israel with their past failures into future obedience', 'The covenant demands are a punishment for rebellion', 'a', 'Deuteronomy 10:12 — "And now, Israel, what doth the LORD thy God require of thee, but to fear the LORD...to walk in all his ways" — the "and now" follows the account of grace in chapter 9.'),
('Deuteronomy', 10, 'adults', 8, 'The growth from seventy souls who went to Egypt to a multitude "as the stars of heaven" in verse 22 deliberately echoes which Abrahamic promise?', 'The promise that Abraham''s descendants would number as the sand of the sea', 'The promise in Genesis 15:5 that Abraham''s seed would be as numerous as the stars of heaven', 'The promise that Jacob''s sons would become twelve great nations', 'The promise that Canaan would be filled with Israel''s children', 'a', 'Deuteronomy 10:22 — "Thy fathers went down into Egypt with threescore and ten persons; and now the LORD thy God hath made thee as the stars of heaven for multitude" — fulfilling Genesis 15:5 and 22:17.');
